def solve(words: Array[String]): Array[Long] = {
  val n = words.length
  val answer = Array.fill(n)(0L)

  def lcp(s1: String, s2: String): Int = {
    val minLen = math.min(s1.length, s2.length)
    var i = 0
    while (i < minLen && s1(i) == s2(i)) i += 1
    i
  }

  for (i <- 0 until n) {
    var maxLcp = 0L
    var left = i - 1
    var right = i + 1

    while (left >= 0 && right < n) {
      val currentLcp = lcp(words(left), words(right))
      maxLcp = math.max(maxLcp, currentLcp.toLong)
      left -= 1
      right += 1
    }

    answer(i) = maxLcp
  }

  answer
}
